import React, { useState } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Calendar, 
  Apple, 
  Dumbbell, 
  Settings,
  LogOut
} from "lucide-react";

// Importación de tus componentes (asegúrate de que los nombres de archivo coincidan)
import { DashboardOverview } from "./dashboard-overview";
import { MembersPage } from "./members";
import { ScheduleManager } from "./schedule-manager";
import { NutritionManager } from "./nutrition-manager";
import { WorkoutsPage } from "./workouts";
import { SettingsPage } from "./settings";

function App() {
  const [activeTab, setActiveTab] = useState('dashboard');

  // Mapeo de pestañas a componentes
  const renderContent = () => {
    const handleSelectMember = (user: any) => {
      console.log('Selected member:', user);
    };

    switch (activeTab) {
      case 'dashboard': return <DashboardOverview />;
      case 'members': return <MembersPage onSelectMember={handleSelectMember} />;
      case 'schedule': return <ScheduleManager />;
      case 'nutrition': return <NutritionManager />;
      case 'workouts': return <WorkoutsPage />;
      case 'settings': return <SettingsPage />;
      default: return <DashboardOverview />;
    }
  };

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'members', label: 'Members', icon: Users },
    { id: 'schedule', label: 'Schedule', icon: Calendar },
    { id: 'nutrition', label: 'Nutrition', icon: Apple },
    { id: 'workouts', label: 'Workouts', icon: Dumbbell },
    { id: 'settings', label: 'Settings', icon: Settings },
  ];

  return (
    <div className="flex min-h-screen bg-[#0a0a0a] text-white font-sans">

      {/* Sidebar Lateral Fijo */}
      <aside className="w-64 bg-[#121212] border-r border-[#2a2a2a] flex flex-col sticky top-0 h-screen">
        <div className="p-8">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-[#39FF14] rounded-xl flex items-center justify-center shadow-[0_0_15px_rgba(57,255,20,0.4)]">
              <Activity className="text-black w-6 h-6" />
            </div>
            <span className="text-xl font-black tracking-tighter italic">GYM<span className="text-[#39FF14]">PRO</span></span>
          </div>
        </div>

        <nav className="flex-1 px-4 space-y-2">
          {menuItems.map((item) => {
            const Icon = item.icon;
            const isActive = activeTab === item.id;
            return (
              <button
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 group ${
                  isActive 
                    ? 'bg-[#39FF14]/10 text-[#39FF14] border border-[#39FF14]/20' 
                    : 'text-gray-400 hover:bg-[#1a1a1a] hover:text-white'
                }`}
              >
                <Icon className={`w-5 h-5 ${isActive ? 'text-[#39FF14]' : 'group-hover:text-[#39FF14]'}`} />
                <span className="font-semibold text-sm">{item.label}</span>
                {isActive && <div className="ml-auto w-1.5 h-1.5 rounded-full bg-[#39FF14] shadow-[0_0_8px_#39FF14]" />}
              </button>
            );
          })}
        </nav>

        <div className="p-4 border-t border-[#2a2a2a]">
          <button className="w-full flex items-center gap-3 px-4 py-3 text-gray-400 hover:text-red-500 hover:bg-red-500/5 rounded-xl transition-colors">
            <LogOut className="w-5 h-5" />
            <span className="font-semibold text-sm">Logout</span>
          </button>
        </div>
      </aside>

      {/* Área de Contenido Principal */}
      <main className="flex-1 p-8 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
}

// Icono auxiliar para el logo
function Activity(props: any) {
  return (
    <svg {...props} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>
  );
}

export default App;
